INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('东方贵族', '渔轮', '动力鼓轮', '东方贵族', 'Oriental Noble F20', 'REEF 生产的渔线轮系列中的一个特殊版本。贵族版本与原来的东方系列不同之处在于，其机械装置经过改进，齿轮比优化，线轴容量提高，摩擦断裂系数强化。专为重型纺车钓法和拖钓而设计。', '7.1:1', '', '', '', '', '20', '动力辅助鼓轮', '15.9kg', 0, '0.82', '', 0, '24', '', '', '', '≥20g', 0, '58.45', 0, '90.38kg', 0, '💧');
