INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Full Metal 60', '渔轮', '新年系列 纺车式', 'Full Metal 60', 'Full Metal 60', 'Full Metal 60 是Trident公司提供的精美复古鱼线轮。 尽管年代久远，它不仅吸引了收藏家的兴趣，而且仍然可以成功地使用钓鱼。 Full Metal 60属于动力纺车轮的类型，由于其设计，能够承受很大的负载。', '4.5:1', '', '', '0.69', '', '6000', '纺车式', '18.2kg', 0, '', '8g', 0, '24', '', '', '', '', 0, '42.09', '5498.8', '49.15kg', 0, '💧');
