INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Overlord 88', '渔轮', '新年系列 纺车式', 'Overlord 88', 'Overlord 88', 'Overlord 系列鱼线轮 Zeiman的生产时间不长，今天，找到这种型号非常成功。 但是除了它们的稀有性之外，Overlord 鱼线轮还具有出色的性能。 它们的机制非常可靠。 它们可以让您进行长距离抛掷，甚至可以处理非常大的鱼。', '4.5:1', '', '', '1.05', '', '8000', '纺车式', '24.5kg', 0, '', '12g', 0, '27', '', '', '', '', 0, '103.22', '17889.25', '81.46kg', 0, '');
