INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('型号 827', '渔轮', '新年系列 纺车式', '型号 827', '型号 827', '三叉戟渔具公司（Trident ）复古纺车轮。型号 827凭借简单而可靠的设计， 即使在具有挑战性的海水钓鱼环境中也能使用。', '4.0:1', '', '', '0.81', '', '8000', '纺车式', '16.5kg', 0, '', '12g', 0, '28', '', '', '', '', 0, '35.44', '4498.5', '44.36kg', 0, '💧');
