INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('奥拉夫HS-LP', '渔轮', '水滴轮', '奥拉夫HS-LP', 'Olaf HS-LP', '低调的奥拉夫 HS LP 被定位为一款通用型号，既适合专业竞技钓鱼，也方便周末休闲垂钓。尺寸小巧却性能不俗，坚固的石墨框架带来出色的结构刚度，也最大限度地降低渔线轮的重量。专有的 CS Ultra 泄力系统可提供顺滑且强劲的曳力表现，而磁力制动系统则可确保在使用各种路亚时实现精准抛投，使奥拉夫 HS LP 成为适用于所有形式作钓的可靠渔线轮。', '', '7.1:1', '', '0.79', '', 'LP', '水滴轮', '8.6kg', 0, '', '≥2.9g', 0, '25', '', '', '', '', 0, '47.80', '6398.6', '34.65kg', 0, '-');
INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('岩浆XHS-LP', '渔轮', '水滴轮', '岩浆XHS-LP', 'Magma XHS-LP', '泽曼渔具公司（Zeiman ）推出的系列新款水滴轮，结合现代设计与尖端工程学，机身采用特殊的耐腐蚀合金，侧板则由碳纤维制成。超轻铝制线轴具有完美的平衡性，CS Ultra 摩擦制动系统确保顺滑且可控的出线，而高精度磁力摩擦刹车则允许精准调节刹车力。这确保了最大程度的顺滑性和远距离抛投的精确度。', '', '8.1:1', '', '0.86', '', 'LP', '水滴轮', '8.9kg', 0, '', '≥2.5g', 0, '25', '', '', '', '', 0, '60.77', '8599.6', '32kg', 0, '-');
