INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Billionaire', '渔轮', '鼓轮', 'Billionaire', 'Billionaire 50R', 'Billionaire – 经过时间考验并倍受欢迎的倍增鱼线轮系列。金属外壳的古典轮廓和令人难以置信的机构可靠性，Billionaire被全世界钓者所熟知。渔轮的舒适手柄非常适合手部，这使得搏鱼非常舒适。Billionaire将在任何钓者的收藏中占有一席之地。用于汲钩钓(jigging)，以及抽停饵和其它重型拟饵。', '', '5.1:1', '', '0.57', '', '5000', '鼓轮', '', '11kg', '', '', 0, '18', '', '', '', '', '≥12g', '19.5', '2298.5', '56.82kg', 0, '');
