INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Billionaire HV', '渔轮', '鼓轮', 'Billionaire HV', 'Billionaire H-Version 60R', 'Billionaire H-Version –来自Trident公司的舒适可靠强大的倍增鱼线轮系列。鱼线轮 Billionaire H-Version拥有一个坚固的铝制机体，蕴藏着可靠的机构。由于具有出色的防腐蚀保护功能，这些鱼线轮也可成功用于海洋捕鱼。该系列的所有鱼线轮均配有加强摩擦制动垫圈。鱼线轮用途 – 用于重型拟饵，汲钩钓(jigging)，拖钓，抽停钓法。有安装鱼线计数器的版本，用于拖钓和垂钓。', '5.1:1', '', '', '0.57', '', '6000', '鼓轮', '', '18kg', '', '', 0, '25', '', '', '', '', '≥18.5g', '54.51', '7509.5', '79kg', 0, '-');
